import LineChart from "@/components/Chart/LineChart";
import AdminLayout from "@/components/Layout/AdminLayout";
import { apiBaseUrl } from "@/config";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import { Shipping } from "@/types";
import { Earnings } from "@/types/chart";
import { ChartDataset } from "chart.js";
import moment from "moment";
import React, { useEffect, useState } from "react";

const EarningReports = () => {
  const [netIncomeData, setNetIncomeData] = useState<number[]>([]);
  const [earningsPerMonth, setEarningPerMonth] = useState<Earnings>({
    january: 0,
    february: 0,
    march: 0,
    april: 0,
    may: 0,
    june: 0,
    july: 0,
    august: 0,
    september: 0,
    october: 0,
    november: 0,
    december: 0,
  });
  const months = [
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
  ];

  const shipping = useCustomSWR<Shipping[]>(`${apiBaseUrl}/shipping`);

  useEffect(() => {
    if (shipping.data) {
      const tempEarning = {
        january: 0,
        february: 0,
        march: 0,
        april: 0,
        may: 0,
        june: 0,
        july: 0,
        august: 0,
        september: 0,
        october: 0,
        november: 0,
        december: 0,
      };
      for (const ship of shipping.data) {
        for (const detail of ship.shippingDetails) {
          const month = moment(detail.createdAt)
            .format("MMMM")
            .toLowerCase() as keyof Earnings;
          tempEarning[month] += detail.costAfter;
        }
      }
      setEarningPerMonth(tempEarning);
    }
  }, [shipping.data]);

  useEffect(() => {
    if (earningsPerMonth) {
      const tempIncome = [];
      for (const key in earningsPerMonth) {
        tempIncome.push(earningsPerMonth[key as keyof Earnings]);
      }
      setNetIncomeData(tempIncome);
    }
  }, [earningsPerMonth]);

  useEffect(() => {
    console.log(netIncomeData);
  }, [netIncomeData]);

  return (
    <AdminLayout>
      <h1 className="uppercase font-semibold text-2xl text-black pt-14">
        Earning Reports by Month
      </h1>
      <div className="h-[600px]">
        <LineChart
          myDatasets={[
            {
              label: "Net Income Datasets Per Month",
              data: netIncomeData,
              borderColor: "blue",
              backgroundColor: "blue",
            },
          ]}
          myLabels={months}
          chartTitle="Net Income Chart"
        />
        {/* <LineChart /> */}
      </div>
    </AdminLayout>
  );
};

export default EarningReports;
